+type QueryEntry = { traits: Trait[]; stores: Store<any>[]; merged: boolean };
+
+function getQueryEntries(params: QueryParameter[], world: World): QueryEntry[] {
+    const entries: QueryEntry[] = [];
+    for (const param of params) {
+        if (isModifier(param)) {
+            if (param.type === 'not') continue;
+            for (const trait of param.traits) if (trait[$internal].type !== 'tag') entries.push({ traits: [trait], stores: [getStore(world, trait)], merged: false });
+        } else if (isAspect(param)) {
+            const traits = param.traits.filter((trait) => trait[$internal].type !== 'tag');
+            entries.push({ traits, stores: traits.map((trait) => getStore(world, trait)), merged: true });
+        } else if (!isRelationPair(param) && param[$internal].type !== 'tag') {
+            entries.push({ traits: [param], stores: [getStore(world, param)], merged: false });
+        }
+    }
+    return entries;
+}
+
+function createEntrySnapshots(entityId: number, entries: QueryEntry[], state: any[], atomic = false): any[] {
+    const snapshots: any[] = [];
+    for (let i = 0; i < entries.length; i++) {
+        const entry = entries[i];
+        if (entry.merged) {
+            const value: Record<string, any> = {};
+            for (let j = 0; j < entry.traits.length; j++) Object.assign(value, entry.traits[j][$internal].get(entityId, entry.stores[j]));
+            state[i] = value;
+            snapshots[i] = atomic ? { ...value } : undefined;
+        } else {
+            const value = entry.traits[0][$internal].get(entityId, entry.stores[0]);
+            state[i] = value;
+            snapshots[i] = atomic && entry.traits[0][$internal].type === 'aos' ? { ...value } : undefined;
+        }
+    }
+    return snapshots;
+}
+
+function commitEntryStates(world: World, entity: Entity, eid: number, query: QueryInstance, entries: QueryEntry[], state: any[], snapshots: any[], mode: 'always' | 'auto' | 'never') {
+    for (let i = 0; i < entries.length; i++) for (let j = 0; j < entries[i].traits.length; j++) {
+        const trait = entries[i].traits[j];
+        const ctx = trait[$internal];
+        const value = entries[i].merged ? Object.fromEntries(Object.keys(trait.schema).filter((key) => key in state[i]).map((key) => [key, state[i][key]])) : state[i];
+        const tracked = mode === 'always' || (mode === 'auto' && (world[$internal].trackedTraits.has(trait) || (query.hasChangedModifiers && query.changedTraits.has(trait))));
+        if (!tracked || mode === 'never') ctx.fastSet(eid, entries[i].stores[j], value);
+        else {
+            let changed = ctx.fastSetWithChangeDetection(eid, entries[i].stores[j], value);
+            if (!changed && ctx.type === 'aos') changed = !shallowEqual(value, snapshots[i]);
+            if (changed) setChanged(world, entity, trait);
+        }
+    }
